            PPD = 100.0 - 95.0 * std::exp(expTest1);
        } else {
            PPD = 100.0;
        }

        if (PPD < 0.0) {
            PPD = 0.0;
        } else if (PPD > 100.0) {
            PPD = 100.0;
        }
        return PPD;
    }

