def calculateDayOfYear(Month: Int, Day: Int, leapYear: Bool) -> Int:
    var daysbefore: List[Int] = List[Int](0, 31, 59, 90, 120, 151, 181, 212, 243, 273, 304, 334)
    var daysbeforeleap: List[Int] = List[Int](0, 31, 60, 91, 121, 152, 182, 213, 244, 274, 305, 335)
    if leapYear:
        return daysbeforeleap[Month - 1] + Day
    return daysbefore[Month - 1] + Day

